<script setup lang="ts">
import { computed, nextTick, onBeforeUnmount, onMounted, ref } from 'vue'
import AsyncState from '@/components/AsyncState.vue'; import ResultSelector from '@/components/ResultSelector.vue'
import { createRound, getSession, listSessions, putRoundResult } from '@/api/practiceSessions'
import { getTodayOnlineReviews } from '@/api/reviews'
import { newEventId, normalizeApiError, type ApiError } from '@/api/client'
import { useAsyncState } from '@/composables/useAsyncState'
import { formatPhonetic } from '@/utils/formatPhonetic'
import { useAuthStore } from '@/stores/auth'
import { allItemsAnswered, nextButtonDisabled, nextButtonLabel, summarize } from '@/views/reviewLogic'
import type { PracticeRound, PracticeSession, ReviewLog, ReviewStatus, TodayReviewSummary } from '@/types/domain'

const state=useAsyncState<PracticeSession[]>([]);const selectedSessionId=ref<number|null>(null);const round=ref<PracticeRound|null>(null);const index=ref(0);const revealed=ref(false);const busy=ref(false);const error=ref<ApiError|null>(null);const results=ref(new Map<number,ReviewLog>());const eventIds=new Map<number,string>();const started=ref(false);const auth=useAuthStore();const today=ref<TodayReviewSummary|null>(null)
const answerRef=ref<HTMLElement>();const statusLive=ref<HTMLElement>()
const session=computed(()=>state.data.value?.find(value=>value.session_id===selectedSessionId.value)||state.data.value?.[0]);const item=computed(()=>session.value?.items?.[index.value]);const result=computed(()=>item.value?results.value.get(item.value.item_id):undefined);const progress=computed(()=>({current:index.value+1,total:session.value?.items?.length||0}));const finished=computed(()=>allItemsAnswered((session.value?.items??[]).map(value=>value.item_id),results.value))
const summary=computed(()=>summarize(results.value));const nextState=computed(()=>({index:index.value,total:progress.value.total}));const nextLabel=computed(()=>nextButtonLabel(nextState.value));const nextDisabled=computed(()=>nextButtonDisabled(nextState.value))
const statusLiveText=computed(()=>{if(error.value)return `未保存：${error.value.message}`;if(!result.value)return '请选择 认识 / 不认识 / 跳过';if(finished.value)return '本轮已完成。';return `${statusText(result.value.status)}。点「下一题」继续。`});const summaryRows=computed(()=>(session.value?.items??[]).map(it=>({item_id:it.item_id,en:it.word.en_word,phonetic:formatPhonetic(it.word.phonetic),cn:it.word.cn_meaning,status:results.value.get(it.item_id)?.status})))
function shortStatus(s:ReviewStatus|undefined){return s==='known'?'认识':s==='unknown'?'不认识':s==='skipped'?'跳过':''}
function statusText(s:ReviewStatus|undefined){const v=shortStatus(s);return v?`已记录：${v}`:''}
const sessionLabel=(value:PracticeSession)=>value.title?.trim()||`复习表 #${value.session_id}`
const reviewTime=(value:string)=>new Date(value).toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit'})
async function prepare(){const loaded=await state.run(async signal=>{const sessions=await listSessions(1,3,signal,'active');const details=await Promise.all(sessions.data.map(value=>getSession(value.session_id,signal)));return details.filter(value=>(value.items?.length||0)>0&&!value.completed_at)}).catch(()=>undefined);if(loaded?.length&&!loaded.some(value=>value.session_id===selectedSessionId.value))selectedSessionId.value=loaded[0].session_id}
async function loadToday(){try{today.value=await getTodayOnlineReviews()}catch{today.value=null}}
function selectSession(sessionId:number){selectedSessionId.value=sessionId;round.value=null;started.value=false;index.value=0;revealed.value=false;results.value=new Map();eventIds.clear();error.value=null}
async function start(){if(!session.value)return;busy.value=true;error.value=null;try{round.value=await createRound(session.value.session_id,'online');started.value=true;index.value=0;revealed.value=false}catch(e){error.value=normalizeApiError(e)}finally{busy.value=false}}
async function choose(status:ReviewStatus){if(!round.value||!item.value||busy.value)return;busy.value=true;error.value=null;const current=item.value;const existing=results.value.get(current.item_id);const eventId=existing?.client_event_id||eventIds.get(current.item_id)||newEventId();eventIds.set(current.item_id,eventId);try{const saved=await putRoundResult(round.value.round_id,current.item_id,status,eventId,existing?.version);results.value=new Map(results.value).set(current.item_id,saved);revealed.value=true;void loadToday();await nextTick();answerRef.value?.focus()}catch(e){error.value=normalizeApiError(e);await nextTick();statusLive.value?.focus()}finally{busy.value=false}}
function previous(){if(index.value>0){index.value--;revealed.value=true}}
function next(){if(index.value<progress.value.total-1){index.value++;revealed.value=Boolean(item.value&&results.value.has(item.value.item_id))}}
function onKey(event:KeyboardEvent){const target=event.target as HTMLElement;if(['INPUT','TEXTAREA','SELECT'].includes(target.tagName)||target.isContentEditable)return;const map:Record<string,ReviewStatus>={1:'known',2:'unknown',3:'skipped'};if(map[event.key]){event.preventDefault();choose(map[event.key]);return}if(event.key==='ArrowRight'&&result.value&&index.value<progress.value.total-1){event.preventDefault();next()}else if(event.key==='ArrowLeft'&&index.value>0){event.preventDefault();previous()}}
onMounted(()=>{void prepare();void loadToday();window.addEventListener('keydown',onKey)});onBeforeUnmount(()=>window.removeEventListener('keydown',onKey))
</script>
<template><section class="review-page"><AsyncState :phase="state.phase.value" :error="state.error.value" empty-text="还没有可用于在线复习的复习表。" @retry="prepare"><template #empty-action><el-button type="primary" @click="$router.push('/daily/generate')">去生成复习表</el-button></template><template v-if="session">
  <div v-if="!started" class="panel review-intro"><span class="intro-mark" aria-hidden="true">◫</span><p class="eyebrow">ONLINE REVIEW</p><h2>选择复习表</h2><div class="session-picker" aria-label="最近三张复习表"><button v-for="candidate in state.data.value" :key="candidate.session_id" type="button" class="session-choice" :class="{selected:candidate.session_id===session.session_id}" :aria-pressed="candidate.session_id===session.session_id" @click="selectSession(candidate.session_id)"><strong>{{ sessionLabel(candidate) }}</strong><span>{{ candidate.items?.length||0 }} 个词</span><small>{{ new Date(candidate.generated_at).toLocaleDateString('zh-CN') }}</small></button></div><p>将复习「{{ sessionLabel(session) }}」中的 {{ session.items?.length||0 }} 个词。在线模式只作为辅助入口。</p><div v-if="error" class="error-box" role="alert">{{ error.message }}</div><el-button type="primary" size="large" :loading="busy" :disabled="!session.items?.length" @click="start">开始在线复习</el-button></div>
  <div v-else-if="finished" class="finish-summary panel" aria-live="polite"><div class="summary-head"><strong>本轮已完成</strong><span class="summary-counts">认识 {{ summary.known }} · 不认识 {{ summary.unknown }} · 跳过 {{ summary.skipped }}（共 {{ summary.total }}）</span></div><ul class="summary-list"><li v-for="row in summaryRows" :key="row.item_id"><span class="sw-en">{{ row.en }}</span><span v-if="row.phonetic" class="sw-pho">{{ row.phonetic }}</span><span class="sw-cn">{{ row.cn }}</span><span class="sw-tag" :class="row.status">{{ shortStatus(row.status) }}</span></li></ul><el-button v-if="auth.role === 'admin'" @click="$router.push('/history')">查看历史</el-button></div>
  <template v-else-if="item"><div class="review-top"><button type="button" class="text-button" :disabled="index===0" @click="previous">← 修改上一题</button><div class="progress-copy"><span>{{ progress.current }} / {{ progress.total }}</span><el-progress :percentage="Math.round((results.size/progress.total)*100)" :show-text="false"/></div><button type="button" class="text-button" :disabled="index>=progress.total-1" @click="next">下一题 →</button></div>
    <article class="flash-card panel" :class="{revealed}"><div class="source-tags"><span v-for="source in item.source_categories" :key="source" class="source-pill">{{ source }}</span></div><p class="card-label">英文</p><h2>{{ item.word.en_word }}</h2><p v-if="item.word.phonetic" class="phonetic">{{ formatPhonetic(item.word.phonetic) }}</p><p v-if="!revealed" class="reveal-hint">先选择本次结果，再查看答案</p><div v-else ref="answerRef" class="answer" tabindex="-1"><hr/><p class="card-label">中文释义</p><strong>{{ item.word.cn_meaning }}</strong><p v-if="item.word.example_sentence" class="example">{{ item.word.example_sentence }}</p></div></article>
    <div class="review-controls panel"><p ref="statusLive" class="status-live" tabindex="-1" aria-live="polite">{{ statusLiveText }}</p><ResultSelector v-if="!revealed" :model-value="null" :disabled="busy" @select="choose"/><div v-else class="locked-row"><span class="locked-badge" :class="result?.status">{{ statusText(result?.status) }}</span><el-button type="primary" :disabled="nextDisabled" @click="next">{{ nextLabel }}</el-button></div></div>
  </template></template></AsyncState>
  <article v-if="today&&(!started||finished)" class="panel today-review"><div class="today-heading"><div><p class="eyebrow">TODAY</p><h2>今日已完成</h2></div><span>{{ today.counts.total }} 个结果</span></div><div class="today-counts"><span>认识 {{ today.counts.known }}</span><span>不认识 {{ today.counts.unknown }}</span><span>跳过 {{ today.counts.skipped }}</span></div><p v-if="!today.items.length" class="today-empty">今天还没有完成在线复习。</p><ul v-else class="today-list"><li v-for="review in today.items" :key="review.review_id"><div class="today-word"><strong>{{ review.en_word }}</strong><small v-if="review.phonetic">{{ formatPhonetic(review.phonetic) }}</small><span>{{ review.cn_meaning }}</span></div><div class="today-meta"><span class="sw-tag" :class="review.status">{{ shortStatus(review.status) }}</span><small v-if="auth.role==='admin'&&review.actor_id" class="review-actor">学员：{{ review.actor_id }}</small><small>{{ review.session_title||`复习表 #${review.session_id}` }} · {{ reviewTime(review.reviewed_at) }}</small></div></li></ul></article>
</section></template>
<style scoped>.review-page{max-width:850px;margin:0 auto}.review-intro{text-align:center;max-width:720px;margin:5vh auto}.review-intro p:not(.eyebrow){color:var(--muted);line-height:1.7}.intro-mark{display:grid;place-items:center;width:70px;height:70px;border-radius:22px;margin:0 auto 18px;background:var(--green-100);color:var(--green-800);font-size:2rem}.session-picker{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px;margin:18px 0;text-align:left}.session-choice{min-height:86px;display:grid;grid-template-columns:1fr auto;gap:4px 8px;padding:12px;border:1px solid var(--line);border-radius:12px;background:#fff;color:var(--ink);cursor:pointer}.session-choice strong{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.session-choice span{color:var(--green-800);font-weight:700}.session-choice small{grid-column:1/-1;color:var(--muted)}.session-choice.selected{border-color:var(--green-800);box-shadow:0 0 0 2px var(--green-100)}.review-top{display:grid;grid-template-columns:1fr minmax(150px,260px) 1fr;align-items:center;gap:12px;margin-bottom:16px}.review-top>:last-child{text-align:right}.text-button{min-height:44px;border:0;background:transparent;color:var(--green-800);cursor:pointer}.text-button:disabled{opacity:.35}.progress-copy{text-align:center;color:var(--muted);font-size:.8rem}.flash-card{min-height:390px;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:36px;overflow:hidden}.source-tags{position:absolute;align-self:flex-start;top:20px}.flash-card{position:relative}.card-label{color:var(--muted);font-size:.74rem;letter-spacing:.12em;text-transform:uppercase}.flash-card h2{font:700 clamp(2.5rem,8vw,4.5rem) Georgia,serif;margin:0}.phonetic{color:var(--green-800);font-size:1.15rem}.reveal-hint{margin-top:36px;color:var(--muted);font-size:.95rem}.answer{width:100%;animation:rise .2s ease}.answer hr{border:0;border-top:1px solid var(--line);margin:28px 0}.answer strong{font-size:1.35rem}.answer .example{color:var(--muted);font-style:italic;margin:18px auto 0;max-width:580px}.review-controls{margin-top:14px}.locked-row{display:flex;align-items:center;justify-content:center;gap:16px;flex-wrap:wrap}.locked-badge{display:inline-flex;align-items:center;min-height:44px;padding:0 18px;border-radius:12px;border:2px solid var(--line);background:#fff;font-weight:700;color:var(--ink)}.locked-badge.known{border-color:#3e8962;background:#e8f5ed;color:#326a4c}.locked-badge.unknown{border-color:var(--red);background:#fff0ef;color:var(--red)}.locked-badge.skipped{border-color:#987226;background:#fff7df;color:#987226}.finish-summary{margin-top:14px;padding-top:14px;border-top:1px dashed var(--line)}.summary-head{display:flex;flex-wrap:wrap;gap:10px;align-items:baseline;justify-content:center;margin-bottom:10px}.summary-counts{color:var(--muted);font-size:.9rem}.summary-list{list-style:none;margin:0 0 14px;padding:0;display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:8px}.summary-list li{display:flex;flex-wrap:wrap;align-items:baseline;gap:6px;padding:8px 10px;border:1px solid var(--line);border-radius:8px;background:#fff;font-size:.88rem}.sw-en{font-weight:700;color:var(--ink)}.sw-pho{color:var(--green-800);font-size:.82rem}.sw-cn{color:var(--muted);flex:1;min-width:60px}.sw-tag{font-size:.74rem;padding:1px 8px;border-radius:10px;border:1px solid currentColor;white-space:nowrap}.sw-tag.known{color:#3e8962;background:#e8f5ed}.sw-tag.unknown{color:var(--red);background:#fff0ef}.sw-tag.skipped{color:#987226;background:#fff7df}.today-review{margin-top:18px}.today-heading{display:flex;align-items:flex-end;justify-content:space-between;gap:12px}.today-heading h2{margin:2px 0}.today-heading>span,.today-empty{color:var(--muted)}.today-counts{display:flex;gap:14px;margin:8px 0 14px;color:var(--muted);font-size:.88rem}.today-list{list-style:none;margin:0;padding:0;display:grid;gap:8px}.today-list li{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:10px 12px;border:1px solid var(--line);border-radius:10px;background:#fff}.today-word{min-width:0;display:flex;align-items:baseline;gap:8px}.today-word strong{font-size:1rem}.today-word small{color:var(--green-800)}.today-word span{min-width:0;color:var(--muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.today-meta{flex:0 0 auto;display:flex;align-items:center;gap:8px}.today-meta small{color:var(--muted)}@keyframes rise{from{opacity:0;transform:translateY(8px)}}@media(max-width:639px){.review-page{margin:-20px -12px -32px}.review-intro{margin:0;border-radius:0}.session-picker{grid-template-columns:1fr}.review-top{padding:10px 12px;margin:0;background:#fff}.flash-card{border-radius:0;min-height:calc(100vh - 360px);box-shadow:none}.review-controls{position:sticky;bottom:calc(66px + env(safe-area-inset-bottom));border-radius:0;margin:0;padding:12px;z-index:10}.review-top .text-button{font-size:.78rem}.flash-card h2{font-size:2.8rem}.today-review{border-radius:0;margin-top:10px}.today-list li,.today-word,.today-meta{align-items:flex-start}.today-list li{display:grid}.today-word{flex-wrap:wrap}.today-word span{flex-basis:100%}.today-meta{justify-content:space-between}}</style>
